mapper.insert:
/* OrgnCnptUserDataMapper.callCnptUserData */
{ CALL P_MDS_CPNT_USR(
				#{i_DATE, mode=IN, jdbcType=VARCHAR}
				, #{O_CODE, mode=OUT, jdbcType=VARCHAR}
				, #{O_MSG, mode=OUT, jdbcType=VARCHAR}
			) }

mapper.select:
	/* OrgnCnptUserDataMapper.getCnptUserDataFileYn*/
        SELECT  COUNT(*) 
        FROM    MDS_AGNCY_MNGR_HST 
        WHERE   FILE_NM = #{mngrFileNm}

mapper.insert:
	/* OrgnCnptUserDataMapper.insertMdsAgncyMngrMst*/
        INSERT INTO MDS_AGNCY_MNGR_MST ( ORG_ID, EFCT_ST_DT, EFCT_FNS_DT, AGNCY_MNGR_DIV_CD, MNGR_MPHON_NO )
    	SELECT ORG_ID, EFCT_ST_DT, EFCT_FNS_DT, AGNCY_MNGR_DIV_CD, MNGR_MPHON_NO
        FROM MDS_AGNCY_MNGR_HST 
        WHERE FILE_NM = #{mngrFileNm} 
        AND EFCT_FNS_DT = '99991231000000' AND MNGR_MPHON_NO IS NOT NULL

mapper.select:
/* OrgnCnptUserDataMapper.getCnptUserMngrMphonNo*/
	 SELECT  MNGR_MPHON_NO
	 FROM    (
	             SELECT ORG_ID, MNGR_MPHON_NO, RANK() OVER(PARTITION BY ORG_ID ORDER BY EFCT_ST_DT DESC, AGNCY_MNGR_DIV_CD DESC) NUM
	             FROM MDS_AGNCY_MNGR_MST
	         )
	 WHERE   NUM = 1
	 AND     ORG_ID = #{orgnId}

/* OrgnCnptUserDataMapper.getCnptUserDataM2MYn*/
	SELECT  count(*) AS cnt
	FROM    ORG_ORGN_INFO_MST A --판매점
	    , MDS_AGNT_INFO B  --조직
	WHERE   A.ORGN_ID = #{orgnId}
	AND     B.FILE_NM = #{agntFileNm}
	AND     A.KT_ORG_ID = B.ORG_ID
	AND     B.CONT_MCTG_CRCLT_CH_CD = 'E0200' --특수
	AND     B.CONT_CRCLT_CH_CD     = 'E0211'  --특판(B2B)

/* OrgnCnptUserDataMapper.getCnptUserBizRegNum*/
	SELECT  BIZ_REG_NUM
	FROM    ORG_ORGN_INFO_MST
	WHERE   ORGN_ID = #{orgnId}
	AND     HGHR_ORGN_CD = #{hghrOrgnCd}

/* OrgnCnptUserDataMapper.getCnptUserDataBizRegNumYn*/
SELECT  COUNT(*) 
FROM    CMN_USR_MST  
WHERE   USR_ID = #{bizRegNum} 
AND     ATTC_SCTN_CD = '30'

/* OrgnCnptUserDataMapper.getCnptUserDataBizRegNumOrgIdYn*/
	SELECT  count(*)
	FROM    CMN_USR_MST
	WHERE   USR_ID = #{bizRegNum}
	AND     ORGN_ID = #{orgnId}
	AND     ATTC_SCTN_CD = '30'

/* OrgnCnptUserDataMapper.getCnptUserDataIdUserCnt*/
	SELECT  count(*)
	FROM    CMN_USR_MST
	WHERE   USR_ID = #{userId}

mapper.insert:
/*OrgnCnptUserDataMapper.insertCnptUserDataAsgnMSt*/
INSERT INTO CMN_USG_GRP_ASGN_MST
(
	USR_ID, GRP_ID, REGST_ID, REGST_DTTM
) VALUES ( 
	#{userId}, #{grpId}, 'SYSTEM', SYSDATE
)

/*OrgnCnptUserDataMapper.insertCnptUserDataAsgnHSt*/
INSERT INTO CMN_USG_GRP_ASGN_HST
(
	USR_ID,GRP_ID,REGST_ID,REGST_DTTM,SEQ_NUM,OPER_TPYE
)
VALUES
(
	#{userId},#{grpId},'SYSTEM',SYSDATE,(SELECT NVL(MAX(TO_NUMBER(SEQ_NUM))+1,1) FROM CMN_USG_GRP_ASGN_HST WHERE USR_ID = #{userId}),'I'
)

mapper.select:
/* OrgnCnptUserDataMapper.getCnptUserDataMphonNumUsrNm*/
	SELECT  COUNT(*)
	FROM    CMN_USR_MST 
	WHERE   USR_ID = #{userId}
	AND     MBLPHN_NUM = #{mngrMphonNo}
	AND     USR_NM = #{orgnSubstrNm}

mapper.update:
	/* OrgnCnptUserDataMapper.updateCnptUserDataMphonNumUsrNm */
     UPDATE  /* +BYPASS_JUVC*/ CMN_USR_MST 
	     SET     USR_NM = #{orgnSubstrNm}
	             , MBLPHN_NUM = #{mngrMphonNo}
	             , RVISN_ID = 'SYSTEM'
	             , RVISN_DTTM = SYSDATE
	     WHERE   USR_ID = #{userId}
